    public static string? GetWhoisServer(string tld) => TldData.TryGetValue(tld, out var info) ? info.WhoisServer : null;
    public static string? GetRdapEndpoint(string tld) => TldData.TryGetValue(tld, out var info) ? info.RdapEndpoint : null;
    public static RegistryInfo? GetRegistryInfo(string tld)
    {
        if (!TldData.TryGetValue(tld, out var info)) return null;
        return new RegistryInfo { Name = info.RegistryName, Website = info.Website ?? "", WhoisServer = info.WhoisServer ?? "", Tld = tld };
    }
